const rows = $input.all();

if (!rows || rows.length === 0) {
  return [{ json: { message: ':white_check_mark: *Aging Tickets Report* -- No open/pending tickets older than 7 days. All clear!' } }];
}

const today = new Date().toISOString().slice(0, 10);
const totalAccounts = rows.length;
const totalTickets = rows.reduce((sum, r) => sum + Number(r.json.ticket_count || 0), 0);

let lines = [];
lines.push(':clock3: *Aging Tickets Report* -- Open/Pending > 7 days');
lines.push('Date: ' + today + ' | Run at 09:00 UTC');
lines.push('');
lines.push('*Account* | *Segment* | *Tickets* | *Oldest Ticket* | *Assignees*');
lines.push('---------|-----------|-----------|-----------------|------------');

for (const row of rows) {
  const name = row.json.account_name || 'Unknown';
  const segment = row.json.account_segment || '-';
  const count = row.json.ticket_count || 0;
  const oldest = row.json.oldest_ticket_date
    ? String(row.json.oldest_ticket_date).slice(0, 10)
    : '-';
  const assignees = row.json.assignees || '-';
  lines.push(name + ' | ' + segment + ' | ' + count + ' | ' + oldest + ' | ' + assignees);
}

lines.push('');
lines.push('*Total:* ' + totalTickets + ' aging tickets across ' + totalAccounts + ' accounts');

return [{ json: { message: lines.join('\n') } }];
